import React, { useState, useEffect } from 'react';
import ProductService from './ProductService';
import './SupplierDashboard.css';

const SupplierDashboard = () => {
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [pricePerDay, setPricePerDay] = useState('');
  const [mainImageFile, setMainImageFile] = useState(null);
  const [additionalImageFiles, setAdditionalImageFiles] = useState([]);
  const [category, setCategory] = useState('Clothing');
  const [subcategory, setSubcategory] = useState('Men');
  const [showProductForm, setShowProductForm] = useState(false);
  const [products, setProducts] = useState([]); // State to hold the products list

  // Fetch products from Firestore when the component mounts
  useEffect(() => {
    const fetchProducts = async () => {
      try {
        const productsSnapshot = await ProductService.getAllProducts();
        const productList = productsSnapshot.docs.map(doc => ({
          id: doc.id,
          ...doc.data()
        }));
        setProducts(productList);
      } catch (error) {
        console.error("Error fetching products:", error);
      }
    };

    fetchProducts();
  }, []); // Empty dependency array means this runs once when component mounts

  const handleAdditionalImagesChange = (e) => {
    setAdditionalImageFiles(e.target.files);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const newProduct = {
      name,
      description,
      pricePerDay: parseInt(pricePerDay),
      category,
      subcategory,
    };

    try {
      console.log("Submitting product:", newProduct);
      await ProductService.addProduct(newProduct, mainImageFile, additionalImageFiles);
      
      // After adding the product, fetch the updated list of products
      const productsSnapshot = await ProductService.getAllProducts();
      const productList = productsSnapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      }));
      setProducts(productList); // Update the product list

      // Clear the form or provide feedback
      setName('');
      setDescription('');
      setPricePerDay('');
      setMainImageFile(null);
      setAdditionalImageFiles([]);
      setShowProductForm(false); // Hide the form after successful submission
      console.log("Product successfully submitted!");
    } catch (error) {
      console.error("Error adding product:", error);
    }
  };

  return (
    <div className="supplier-dashboard">
      <div className="content">
        <h1>Supplier Dashboard</h1>

        <div className="add-product-section">
          <button className="open-form-button" onClick={() => setShowProductForm(true)}>
            Add Product
          </button>

          {showProductForm && (
            <div className="form-popup">
              <div className="form-container">
                <form onSubmit={handleSubmit} className="add-product-form">
                  <label>
                    Name:
                    <input
                      type="text"
                      value={name}
                      onChange={(e) => setName(e.target.value)}
                      required
                    />
                  </label>
                  <label>
                    Description:
                    <textarea
                      value={description}
                      onChange={(e) => setDescription(e.target.value)}
                      required
                    />
                  </label>
                  <label>
                    Price per Day:
                    <input
                      type="number"
                      value={pricePerDay}
                      onChange={(e) => setPricePerDay(e.target.value)}
                      required
                    />
                  </label>
                  <label>
                    Main Image:
                    <input
                      type="file"
                      accept="image/*"
                      onChange={(e) => setMainImageFile(e.target.files[0])}
                      required
                    />
                  </label>
                  <label>
                    Additional Images:
                    <input
                      type="file"
                      accept="image/*"
                      multiple
                      onChange={handleAdditionalImagesChange}
                    />
                    {additionalImageFiles.length > 0 && (
                      <div className="image-preview">
                        {Array.from(additionalImageFiles).map((file, index) => (
                          <img key={index} src={URL.createObjectURL(file)} alt={`Additional ${index + 1}`} />
                        ))}
                      </div>
                    )}
                  </label>
                  <label>
                    Category:
                    <select
                      value={category}
                      onChange={(e) => setCategory(e.target.value)}
                    >
                      <option value="Clothing">Clothing</option>
                      <option value="Footwear">Footwear</option>
                      <option value="Gear">Gear</option>
                      <option value="Accessories">Accessories</option>
                    </select>
                  </label>
                  <label>
                    Subcategory:
                    <select
                      value={subcategory}
                      onChange={(e) => setSubcategory(e.target.value)}
                    >
                      {category === 'Clothing' && (
                        <>
                          <option value="Men">Men's Clothing</option>
                          <option value="Women">Women's Clothing</option>
                          <option value="Kids">Kids' Clothing</option>
                        </>
                      )}
                      {category === 'Footwear' && (
                        <>
                          <option value="Men">Men's Footwear</option>
                          <option value="Women">Women's Footwear</option>
                          <option value="Kids">Kids' Footwear</option>
                        </>
                      )}
                      {category === 'Gear' && (
                        <>
                          <option value="Camp Furniture">Camp Furniture</option>
                          <option value="Camp Kitchen">Camp Kitchen</option>
                          <option value="Packs">Packs</option>
                          <option value="Sleep Systems">Sleep Systems</option>
                          <option value="Tents & Bivvies">Tents & Bivvies</option>
                          <option value="Additional Gear">Additional Gear</option>
                        </>
                      )}
                      {category === 'Accessories' && (
                        <>
                          <option value="Clothing Accessories">Clothing Accessories</option>
                          <option value="Footwear Accessories">Footwear Accessories</option>
                          <option value="Additional Accessories">Additional Accessories</option>
                        </>
                      )}
                    </select>
                  </label>

                  <button type="submit" className="add-product-button">
                    Add product
                  </button>
                  <button className="close-form-button" onClick={() => setShowProductForm(false)}>
                    Close
                  </button>
                </form>
              </div>
            </div>
          )}
        </div>
<br></br>
        {/* Product History Section */}
        <div className="product-history">
          <h2>Product History</h2>
          {products.length > 0 ? (
            <ul>
              {products.map((product) => (
                <li key={product.id} className="product-item">
                  <h3>{product.name}</h3>
                  <p>{product.description}</p>
                  <p>Price per Day: ${product.pricePerDay}</p>
                </li>
              ))}
            </ul>
          ) : (
            <p>No products added yet.</p>
          )}
        </div>
      </div>
    </div>
  );
};

export default SupplierDashboard;
